def generate_all_subsets(nums):
    n = len(nums)
    power_set_size = 1 << n  # This is 2^n

    result = []
    for i in range(power_set_size):
        current_subset = []
        for j in range(n):
            # Check if the j-th bit of i is set
            if (i >> j) & 1:
                current_subset.append(nums[j])
        result.append(current_subset)
    return result
